namespace iFit.Api.Zendesk
{
	public interface IZendeskApi
	{
		[Post("/api/v2/requests")]
		Task<Request.CreateRequestResponse> CreateRequest([Body] Request request, CancellationToken token = default(CancellationToken));
	}
	public class ConnectivityException : Exception
	{
		public ConnectivityException(string message = null)
			: base(message)
		{
		}
	}
	public class ConnectivityTryAgainLaterException : Exception
	{
		public ConnectivityTryAgainLaterException(string message = null)
			: base(message)
		{
		}
	}
	public interface IZendeskApiService
	{
		IZendeskApi Service { get; }
	}
	public class ZendeskApiService : IZendeskApiService
	{
		public const string Url = "https://ifit.zendesk.com";

		private readonly IZendeskApi zendeskApi;

		public IZendeskApi Service => zendeskApi;

		public ZendeskApiService(string url = "https://ifit.zendesk.com")
		{
			HttpClient client = new HttpClient
			{
				BaseAddress = new Uri(url)
			};
			zendeskApi = RestService.For<IZendeskApi>(client);
		}
	}
	[ExcludeFromCodeCoverage]
	[DebuggerNonUserCode]
	[Preserve]
	[Obfuscation(Exclude = true)]
	internal class AutoGeneratedIZendeskApi : IZendeskApi
	{
		private readonly IRequestBuilder requestBuilder;

		public HttpClient Client { get; protected set; }

		public AutoGeneratedIZendeskApi(HttpClient client, IRequestBuilder requestBuilder)
		{
			Client = client;
			this.requestBuilder = requestBuilder;
		}

		Task<Request.CreateRequestResponse> IZendeskApi.CreateRequest(Request request, CancellationToken token)
		{
			object[] arg = new object[2] { request, token };
			return (Task<Request.CreateRequestResponse>)requestBuilder.BuildRestResultFuncForMethod("CreateRequest", new Type[2]
			{
				typeof(Request),
				typeof(CancellationToken)
			})(Client, arg);
		}
	}
}
