			public string subject { get; set; }

			public string[] tags { get; set; }

			public Comment comment { get; set; }

			public List<CustomField> custom_fields { get; set; }
		}

		public class CreateRequestResponse
		{
			public class Request
			{
				public string url { get; set; }

				public int id { get; set; }
			}

			public Request request { get; set; }
		}

		public const string AnonymousName = "anon";

		private const long IfitUserCustomFieldId = 20963599L;

		private const long ZenDeskPhoneNumberFieldId = 360004544012L;

		private const long ZenDeskAddressFieldId = 360004543832L;

		private const long ZenDeskCityFieldId = 360004544392L;

		private const long ZenDeskStateFieldId = 360004544412L;

		private const long ZenDeskZipFieldId = 360004590171L;

		private const long ZenDeskEquipmentSelectionFieldId = 360047381671L;

		public RequestBody request { get; protected set; }

		public Request(string username, string name, string email, string equipmentType, string description, string feedback)
		{
			request = new RequestBody
			{
				ticket_form_id = 360003162152L,
				requester = new Requester
				{
					name = name,
					email = email
				},
				comment = new Comment
				{
					body = feedback
				},
				subject = username + ": " + description,
				tags = new string[1] { "feedback" },
				custom_fields = new List<CustomField>
				{
					new CustomField
					{
						id = 20963599L,
						value = username
					},
					new CustomField
					{
						id = 360004544012L,
						value = "1234567890"
					},
					new CustomField
					{
						id = 360004543832L,
						value = "unknown"
					},
					new CustomField
					{
						id = 360004544392L,
						value = "unknown"
					},
					new CustomField
					{
						id = 360004544412L,
						value = "unknown"
					},
					new CustomField
					{
						id = 360004590171L,
						value = "unknown"
					},
					new CustomField
					{
						id = 360047381671L,
						value = equipmentType
					}
				}
			};
		}

		public static async Task<CreateRequestResponse> Create(string username, string name, string email, string equipmentType, string subject, string feedback, IZendeskApiService zendeskApi = null, IConnectivity connectivity = null)
		{
			if (connectivity == null)
			{
				connectivity = CrossConnectivity.Current;
			}
			if (!connectivity.IsConnected)
			{
				throw new ConnectivityException("Not connected on Zendesk create request call");
			}
			IZendeskApiService obj = zendeskApi ?? new ZendeskApiService();
			Request request = new Request(username, name, email, equipmentType, subject, feedback);
			return await obj.Service.CreateRequest(request);
		}
	}
